// lib/main.dart
import 'package:flutter/material.dart';
import 'config/env_config.dart';
import 'screens/home_screen.dart';

void main() async {
  WidgetsFlutterBinding.ensureInitialized();

  try {
    await EnvConfig.initialize();
  } catch (e) {
    debugPrint('Warning: Could not load .env file: $e');
    debugPrint('Create a .env file in the project root with:');
    debugPrint('  AWS_ACCESS_KEY_ID=your_key');
    debugPrint('  AWS_SECRET_ACCESS_KEY=your_secret');
    debugPrint('  GOOGLE_CLOUD_API_KEY=your_key');
    debugPrint('  S3_BUCKET_NAME=your_bucket');
    debugPrint('  AWS_REGION=us-east-1');
  }

  runApp(const PhotoAnalyzerApp());
}

class PhotoAnalyzerApp extends StatelessWidget {
  const PhotoAnalyzerApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Photo Analyzer',
      debugShowCheckedModeBanner: false,
      theme: ThemeData(
        colorSchemeSeed: Colors.blue,
        useMaterial3: true,
        brightness: Brightness.light,
      ),
      home: const HomeScreen(),
    );
  }
}

